package com.company.supervision.infrastructure.security;
import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Component;import javax.crypto.Cipher;import javax.crypto.spec.GCMParameterSpec;import javax.crypto.spec.SecretKeySpec;import java.nio.charset.StandardCharsets;import java.security.*;import java.util.*;
@Component public class SecretCipher{private final SecretKeySpec key;private final SecureRandom random=new SecureRandom();public SecretCipher(@Value("${supervision.crypto-key:}")String source){if(source==null||source.isBlank())throw new IllegalStateException("SUPERVISION_CRYPTO_KEY must be configured");try{key=new SecretKeySpec(MessageDigest.getInstance("SHA-256").digest(source.getBytes(StandardCharsets.UTF_8)),"AES");}catch(Exception e){throw new IllegalStateException(e);}}public String encrypt(String raw){if(raw==null||raw.isBlank())return null;try{byte[]iv=new byte[12];random.nextBytes(iv);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,key,new GCMParameterSpec(128,iv));byte[]out=c.doFinal(raw.getBytes(StandardCharsets.UTF_8));byte[]all=new byte[iv.length+out.length];System.arraycopy(iv,0,all,0,iv.length);System.arraycopy(out,0,all,iv.length,out.length);return Base64.getEncoder().encodeToString(all);}catch(Exception e){throw new IllegalStateException("Secret encryption failed",e);}}public String decrypt(String value){if(value==null)return null;try{byte[]all=Base64.getDecoder().decode(value);byte[]iv=Arrays.copyOfRange(all,0,12);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,key,new GCMParameterSpec(128,iv));return new String(c.doFinal(Arrays.copyOfRange(all,12,all.length)),StandardCharsets.UTF_8);}catch(Exception e){throw new IllegalStateException("Secret decryption failed",e);}}public String mask(String value){return value==null?null:"******";}}